/**
 * Convert lat/lng to Mercator x/y (0-1 normalized, y inverted for screen coords)
 * @param {number} lat
 * @param {number} lng
 * @returns {{ x: number, y: number }}
 */
function latLngToMercator(lat, lng) {
  const x = (lng + 180) / 360;
  const latRad = lat * Math.PI / 180;
  const mercN = Math.log(Math.tan(Math.PI / 4 + latRad / 2));
  const y = 0.5 - mercN / (2 * Math.PI);
  return { x, y };
}

/**
 * Get airport display tier for map rendering
 * Tier 1 (large dot): 50+ routes
 * Tier 2 (medium dot): 10-49 routes
 * Tier 3 (small dot): <10 routes
 */
function getAirportTier(iata) {
  const ap = AIRPORTS[iata];
  if (!ap) return 3;
  if (ap.routeCount >= 50) return 1;
  if (ap.routeCount >= 10) return 2;
  return 3;
}

/**
 * Get all airports as sorted array
 */
function getAllAirports() {
  return Object.values(AIRPORTS);
}

/**
 * Get airports by continent
 */
function getAirportsByContinent(cont) {
  return Object.values(AIRPORTS).filter(a => a.continent === cont);
}

if (typeof module !== 'undefined') {
  module.exports = { AIRPORTS, latLngToMercator, getAirportTier, getAllAirports, getAirportsByContinent };
}
